Here are the public test cases for feature1_dsn_components:
{
  "description": "Parses a monitoring endpoint address into connection fields and the envelope submission path.",
  "cases": [
    {
      "input": {
        "dsn": "http://12345:67890@telemetry.example.com:3000/ingest/42"
      },
      "expected_output": "project_id=42\npublic_key=12345\nsecret_key=67890\nscheme=http\nhost=telemetry.example.com\nport=3000\npath=/ingest\ncanonical=http://12345:67890@telemetry.example.com:3000/ingest/42\nenvelope_endpoint=/ingest/api/42/envelope/"
    }
  ]
}

